import { isAbsoluteSize } from "../../cardContainer/helpers/isAbsoluteSize";
import { DeviceType } from "../../commonHelpers/hooks/deviceType";
export const useCardSizeState = (deviceType, scrollableContent, fullWidth, fullHeight, autoHeight, size) => {
    const isMobile = deviceType === DeviceType.Mobile;
    const isAbsolute = isAbsoluteSize(size);
    const isRelative = !isAbsolute;
    let isAutoHeight = autoHeight;
    let isScrollable = scrollableContent && !autoHeight;
    let isFullWidth = fullWidth;
    let isFullHeight = fullHeight && !autoHeight;
    if (isRelative) {
        if (isMobile) {
            isScrollable = false;
            isFullHeight = false;
        }
    }
    else if (isMobile) {
        isScrollable = false;
        isFullHeight = false;
        isAutoHeight = !size.height || isAutoHeight;
        isFullWidth = !size.width || isFullWidth;
    }
    return {
        isAutoHeight,
        isScrollable,
        isFullWidth,
        isFullHeight
    };
};
