import { isAbsoluteSize } from "../helpers/isAbsoluteSize";
/* eslint-disable complexity */
export const useAbsoluteSize = (size, isMobile, autoHeight, fullWidth) => {
    /* eslint-enable complexity */
    if (!isAbsoluteSize(size)) {
        return {};
    }
    if (isMobile) {
        // {width, height}
        if (!autoHeight && !fullWidth && size.height) {
            return {
                minHeight: `${size.height}px`
            };
        }
        // {width}
        if (autoHeight && !fullWidth) {
            return {};
        }
        // {height}
        if (!autoHeight && fullWidth && size.height) {
            return {
                minHeight: `${size.height}px`
            };
        }
        // {}
        return {};
    }
    // {width, height}
    if (!autoHeight && !fullWidth && size.width && size.height) {
        return {
            width: `${size.width}px`,
            height: `${size.height}px`
        };
    }
    // {width}
    if (autoHeight && !fullWidth && size.width) {
        return {
            width: `${size.width}px`
        };
    }
    // {height}
    if (!autoHeight && fullWidth && size.height) {
        return {
            height: `${size.height}px`
        };
    }
    // {}
    return {};
};
