import { CheckboxState } from "../checkbox/checkboxState";
import { getComponentText } from "../commonHelpers/reactHelpers/reactHelpers";
export const getItemIdByIndex = (state, index) => [...state.keys()][index];
export const getItemIndexById = (state, id) => [...state.keys()].indexOf(id);
export const updateItemState = (initialState, multiselect, updatedId, newState) => {
    const temp = new Map(initialState);
    let isUpdated = false;
    if (!temp.has(updatedId)) {
        return [temp, isUpdated];
    }
    let prevState = temp.get(updatedId);
    isUpdated = prevState !== newState;
    temp.set(updatedId, newState);
    if (!multiselect) {
        let onItem = newState !== CheckboxState.Off && updatedId;
        temp.forEach((itemState, itemId) => {
            if (itemState !== CheckboxState.Off && !onItem) {
                onItem = itemId;
            }
            if (itemId !== onItem) {
                prevState = temp.get(itemId);
                isUpdated = isUpdated || prevState !== CheckboxState.Off;
                temp.set(itemId, CheckboxState.Off);
            }
        });
    }
    return [temp, isUpdated];
};
export const searchItemIndex = (items, searchStr) => {
    if (!searchStr) {
        return -1;
    }
    return items.findIndex(item => {
        const content = getComponentText(item.children);
        return content.toLocaleLowerCase().indexOf(searchStr.toLocaleLowerCase()) > -1;
    });
};
export const getFirstIndex = (items) => (items.length > 0 ? 0 : -1);
export const getLastIndex = (items) => (items.length > 0 ? items.length - 1 : -1);
export const getNextIndex = (currIndex, items) => {
    if (items.length === 0) {
        return -1;
    }
    return currIndex + 1 >= items.length ? 0 : currIndex + 1;
};
export const getPrevIndex = (currIndex, items) => {
    if (items.length === 0) {
        return -1;
    }
    return currIndex <= 0 || currIndex >= items.length ? items.length - 1 : currIndex - 1;
};
export const getFirstActiveIndex = (state, items, multiselect) => {
    for (let i = 0; i < items.length; i++) {
        if (state.get(items[i].id) === CheckboxState.On) {
            return i;
        }
    }
    return multiselect && items.length > 0 ? 0 : -1;
};
export const getItemsState = (items, value, multiselect) => {
    let forceUncheck = false;
    return items.reduce((res, item) => {
        const itemState = value.get(item.id);
        if (!itemState || itemState === CheckboxState.Off || forceUncheck) {
            return res.set(item.id, CheckboxState.Off);
        }
        if (!multiselect) {
            forceUncheck = true;
        }
        return res.set(item.id, itemState);
    }, new Map());
};
export const getInitialState = ({ items, value = new Map([]), multiselect }) => ({
    itemsState: getItemsState(items, value, multiselect),
    isItemsStateChanged: false,
    activeIndex: -1,
    searchStr: "",
    level: ""
});
