import { createCurrentlySelectedOptions } from "./groupsFilterStatesHelper";
export const getAdvancedFilterValue = ({ blocks, state, isWithColor, uncheckedItems, uncheckedAdvancedState, listLimit }) => {
    const getGroupsMenuValue = (limit, value) => {
        if (!value || value !== "advancedGroups") {
            return [];
        }
        const result = createCurrentlySelectedOptions(state, value, isWithColor || false, uncheckedItems, limit, uncheckedAdvancedState);
        return result;
    };
    const groupsBlocks = blocks.map((val) => getGroupsMenuValue(listLimit, val)).filter(el => el.length);
    return groupsBlocks;
};
export const getAdvancedLabel = ({ groupsBlocks }) => {
    const combinedLabel = groupsBlocks.reduce((outerAccumulator, group) => {
        const groupLabel = group.reduce((innerAccumulator, item) => {
            if (item.label) {
                const updatedAccumulator = innerAccumulator + item.label;
                return updatedAccumulator;
            }
            return innerAccumulator;
        }, "");
        if (!groupLabel) {
            return outerAccumulator;
        }
        const updatedAccumulator = outerAccumulator + groupLabel;
        return updatedAccumulator;
    }, "");
    return combinedLabel;
};
