export function getSizeClass(className, size) {
    // eslint-disable-next-line @typescript-eslint/switch-exhaustiveness-check
    switch (size) {
        case "XXL":
            return `${className}--extra-extra-large`;
        case "XL":
            return `${className}--extra-large`;
        case "L":
            return `${className}--large`;
        case "M":
            return `${className}--medium`;
        case "S":
            return `${className}--small`;
        case "XS":
            return `${className}--extra-small`;
        case "XXS":
            return `${className}--extra-extra-small`;
        default:
            return "";
    }
}
