import { DEFAULT_RELATION_OPERATOR, getDefaultFilterState, isEntireOrganization, simplifyFilterState, toFilterState } from "../groupsFilterRaw/groupsHelper";
import { RelationOperator } from "../groupsFilterRaw/groupsFilterInterfaces";
import { isFilterStateLeafItem } from "./advancedGroupsFilterHelper";
export const prepareCurrentFilterState = (state) => {
    if (!state) {
        return [{ sectionState: getDefaultFilterState(), interSectionRelation: DEFAULT_RELATION_OPERATOR }];
    }
    const sectionItems = [];
    const addToSelections = (item) => sectionItems.push(item);
    const setItemState = (parentItem, prevRelation = DEFAULT_RELATION_OPERATOR) => {
        if (!isFilterStateLeafItem(parentItem)) {
            return parentItem.items.map(item => setItemState(item, parentItem.relation));
        }
        return addToSelections({
            interSectionRelation: prevRelation,
            sectionState: Object.assign({}, parentItem)
        });
    };
    setItemState(state);
    return sectionItems;
};
export const prepareToFilterState = (state) => {
    if (state.length === 1) {
        return state[0].sectionState;
    }
    const getState = (sect) => {
        const getId = entity => entity.id;
        return Object.assign(Object.assign({}, sect), { sectionState: Object.assign(Object.assign({}, sect.sectionState), { items: sect.sectionState.items.map(getId).sort() }) });
    };
    const preparedState = state.reduce((prevState, section) => {
        const itemState = getState(section);
        if (state.length > 1 && isEntireOrganization(itemState.sectionState) && itemState.sectionState.relation === RelationOperator.OR) {
            return prevState;
        }
        if (!Object.keys(prevState).length) {
            return itemState.sectionState;
        }
        return {
            relation: itemState.interSectionRelation,
            items: [prevState, itemState.sectionState]
        };
    }, {});
    return Object.keys(preparedState).length ? toFilterState(simplifyFilterState(preparedState)) : getDefaultFilterState();
};
